from tenacity import (
    retry,
    stop_after_attempt,
    wait_exponential_jitter,
    retry_if_exception_type,
    before_sleep_log,
)
import httpx
import logging

logger = logging.getLogger(__name__)

@retry(
    stop=stop_after_attempt(4),
    wait=wait_exponential_jitter(initial=1, max=30, jitter=1),
    retry=retry_if_exception_type((httpx.TimeoutException, httpx.HTTPStatusError)),
    before_sleep=before_sleep_log(logger, logging.WARNING),
    reraise=True,   # re-raise the last exception after all attempts
)
def fetch_stock_price(ticker: str) -> dict:
    resp = httpx.get(f"https://api.finance.example.com/price/{ticker}", timeout=5)
    resp.raise_for_status()
    return resp.json()

# Rate-limit aware: only retry on 429 and 5xx, not 4xx
def is_retryable_http(exc: Exception) -> bool:
    if isinstance(exc, httpx.HTTPStatusError):
        return exc.response.status_code in (429, 500, 502, 503, 504)
    return isinstance(exc, httpx.TimeoutException)

@retry(
    stop=stop_after_attempt(5),
    wait=wait_exponential_jitter(initial=2, max=60),
    retry=retry_if_exception_type(httpx.HTTPStatusError) | retry_if_exception_type(httpx.TimeoutException),
    reraise=True,
)
def call_llm_api(payload: dict) -> dict:
    """Retry LLM API calls on rate limits and server errors."""
    resp = httpx.post("https://api.openai.com/v1/chat/completions", json=payload, timeout=30)
    resp.raise_for_status()
    return resp.json()

import time
import httpx
from tenacity import retry, stop_after_attempt, wait_base, RetryCallState

class WaitRetryAfter(wait_base):
    """tenacity wait strategy that reads the Retry-After header."""
    def __init__(self, fallback_seconds: float = 5.0):
        self.fallback = fallback_seconds

    def __call__(self, retry_state: RetryCallState) -> float:
        exc = retry_state.outcome.exception()
        if isinstance(exc, httpx.HTTPStatusError) and exc.response.status_code == 429:
            header = exc.response.headers.get("Retry-After")
            if header:
                return float(header)
        return self.fallback

@retry(
    stop=stop_after_attempt(5),
    wait=WaitRetryAfter(fallback_seconds=5.0),
    reraise=True,
)
def call_openai_with_rate_limit_respect(payload: dict) -> dict:
    resp = httpx.post(
        "https://api.openai.com/v1/chat/completions",
        headers={"Authorization": f"Bearer {OPENAI_API_KEY}"},
        json=payload,
        timeout=30,
    )
    resp.raise_for_status()
    return resp.json()

from openai import OpenAI
import json

client = OpenAI()

def run_tool(name: str, args: dict) -> str:
    """Dispatch tool call; always return a string result (never raise)."""
    try:
        if name == "get_order":
            result = get_order(**args)
            if result is None:
                return json.dumps({"error": f"Order '{args.get('order_id')}' not found."})
            return json.dumps(result)
        elif name == "list_orders_by_status":
            return json.dumps(list_orders_by_status(**args))
        else:
            return json.dumps({"error": f"Unknown tool: {name}"})
    except TypeError as e:
        # LLM passed wrong argument types
        return json.dumps({"error": f"Invalid arguments: {e}"})
    except Exception as e:
        return json.dumps({"error": str(e)})

def run_agent_with_llm_retry(user_message: str, max_turns: int = 6) -> str:
    messages = [{"role": "user", "content": user_message}]
    for _ in range(max_turns):
        response = client.chat.completions.create(
            model="gpt-4o-mini",
            messages=messages,
            tools=TOOLS,
            tool_choice="auto",
        )
        choice = response.choices[0]
        messages.append(choice.message)

        if choice.finish_reason == "stop":
            return choice.message.content

        # Pass all tool results (including errors) back to the LLM
        for tc in choice.message.tool_calls:
            args = json.loads(tc.function.arguments)
            result = run_tool(tc.function.name, args)   # never raises
            messages.append({
                "role": "tool",
                "tool_call_id": tc.id,
                "content": result,   # error messages land here
            })
            # LLM sees the error and may call a different tool or correct the args

